import sys

def main():
    MOD = 1000000007
    R, C = map(int, sys.stdin.readline().split())
    grid = [sys.stdin.readline().strip() for _ in range(R)]

    dp = [[0] * C for _ in range(R)]

    for i in range(R):
        for j in range(C):
            if grid[i][j] == '#':
                continue
            if i == 0 and j == 0:
                dp[i][j] = 1
            elif i == 0:
                dp[i][j] = dp[i][j-1]
            elif j == 0:
                dp[i][j] = dp[i-1][j]
            else:
                dp[i][j] = (dp[i-1][j] + dp[i][j-1]) % MOD

    print(dp[-1][-1])

if __name__ == "__main__":
    main()
